            remote.into(),
            format!("+refs/pull/{pr_number}/head:{pr_head_ref}"),
        ],
    )
    .with_context(|| {
        format!("failed to fetch PR ref `refs/pull/{pr_number}/head` from remote `{remote}`")
    })?;

    run_git(
