    /// 2) `ToolResult.call_id`
    pub fn semantic_call_id(&self) -> Option<&str> {
        if let Some(call_id) = self.attr_str(ATTR_SEMANTIC_CALL_ID) {
            return Some(call_id);
        }

        if let EventType::ToolResult {
            call_id: Some(call_id),
            ..
        } = &self.event_type
        {
            let trimmed = call_id.trim();
            if !trimmed.is_empty() {
                return Some(trimmed);
            }
        }
        None
    }
