        std::fs::create_dir_all(tmp.path().join(".git")).expect("create .git");
        let nested = tmp.path().join("x/y/z");
        std::fs::create_dir_all(&nested).expect("create nested");
        assert_eq!(find_repo_root(&nested), Some(tmp.path().to_path_buf()));
