        fn drop(&mut self) {
            if let Some(value) = &self.previous {
                // SAFETY: tests serialize environment mutation with `env_test_lock`.
                unsafe { std::env::set_var(self.key, value) };
            } else {
                // SAFETY: tests serialize environment mutation with `env_test_lock`.
                unsafe { std::env::remove_var(self.key) };
            }
        }
    }

