   111	fn public_feed_cache_key(query_pairs: &[(String, String)]) -> String {
   112	    let mut sorted = query_pairs.to_vec();
   113	    sorted.sort_unstable_by(|a, b| a.0.cmp(&b.0).then_with(|| a.1.cmp(&b.1)));
   114	
   115	    if sorted.is_empty() {
   116	        return "https://cache.opensession.io/api/sessions".to_string();
   117	    }
   118	
   119	    let mut encoded = String::new();
   120	    for (idx, (k, v)) in sorted.iter().enumerate() {
   121	        if idx > 0 {
   122	            encoded.push('&');
   123	        }
   124	        encoded.push_str(&urlencoding::encode(k));
   125	        encoded.push('=');
   126	        encoded.push_str(&urlencoding::encode(v));
   127	    }
   128	    format!("https://cache.opensession.io/api/sessions?{encoded}")
   129	}
